DROP TABLE `Customer Information`;

CREATE DATABASE `Banking Analysis 1`;
USE `Banking Analysis 1`;
CREATE TABLE IF NOT EXISTS `Customer Information` (
`S.No` int not null,
`Customer Id` int,
`Customer Name` Varchar (40),
`Account Number` int,
`Account Type` varchar(25),
`Account Status` varchar(25),
`Branch Name` varchar(40),
`Branch Code` int,
`Customer Age` int,
`Customer Marital Status` varchar(20),
`Customer Location` varchar(35));

SELECT * FROM `Customer Information`;





